    const rawWidth = Number.isFinite(attrWidth) && attrWidth > 0
      ? attrWidth
      : Number(svg?.getAttribute?.('width'));
    const rawHeight = Number.isFinite(attrHeight) && attrHeight > 0
      ? attrHeight
      : Number(svg?.getAttribute?.('height'));
